<template>
	<view class="container">
		<!-- 状态tab -->
		<view class="status-tabs">
			<view 
				v-for="(status, index) in statusTabs" 
				:key="index"
				class="tab-item"
				:class="{ active: currentStatus === status.value }"
				@click="switchStatus(status.value)">
				<text>{{ status.label }}</text>
				<text v-if="status.count > 0" class="badge">{{ status.count }}</text>
			</view>
		</view>
		
		<!-- 任务列表 -->
		<scroll-view 
			scroll-y 
			class="list-container"
			@scrolltolower="loadMore"
			refresher-enabled
			@refresherrefresh="refresh">
			<view v-for="item in taskList" :key="item._id" class="task-item" @click="goToDetail(item._id)">
				<view class="task-header">
					<view class="task-title-row">
						<text class="task-title">{{ item.title }}</text>
						<text v-if="item.urgency === '特急'" class="tag tag-danger">特急</text>
						<text v-else-if="item.urgency === '紧急'" class="tag tag-warning">紧急</text>
					</view>
					<text class="task-source">{{ item.source }}</text>
				</view>
				
				<view class="task-info">
					<view class="info-row">
						<text class="info-label">涉及人员：</text>
						<text class="info-value">{{ item.parties || '未填写' }}</text>
					</view>
					<view class="info-row">
						<text class="info-label">发生位置：</text>
						<text class="info-value">{{ item.location?.address || '未填写' }}</text>
					</view>
					<view class="info-row">
						<text class="info-label">发生次数：</text>
						<text class="info-value">{{ item.occur_count || 1 }}次</text>
					</view>
				</view>
				
				<view class="task-footer">
					<text class="task-time">{{ formatTime(item.assign_time || item.create_time) }}</text>
					<text class="status-text" :class="getStatusClass(item.status)">{{ item.status }}</text>
				</view>
				
				<view v-if="item.status === '待回访'" class="task-action">
					<button class="btn-visit" @click.stop="goToDetail(item._id)">立即回访</button>
				</view>
			</view>
			
			<view v-if="loading" class="loading">加载中...</view>
			<view v-if="!hasMore && taskList.length > 0" class="no-more">没有更多了</view>
			<view v-if="taskList.length === 0 && !loading" class="empty">
				<text class="empty-icon">📋</text>
				<text class="empty-text">暂无任务</text>
			</view>
		</scroll-view>
	</view>
</template>

<script setup>
	import { ref, reactive, computed, onMounted } from 'vue'
	import { onShow } from '@dcloudio/uni-app'
	import { useUserStore } from '@/store/user'
	
	const userStore = useUserStore()
	
	const statusTabs = ref([
		{ label: '待回访', value: '待回访', count: 0 },
		{ label: '处理中', value: '处理中', count: 0 },
		{ label: '已完成', value: '已化解', count: 0 }
	])
	const currentStatus = ref('待回访')
	
	const taskList = ref([])
	const loading = ref(false)
	const page = ref(1)
	const pageSize = 10
	const hasMore = ref(true)
	
	onMounted(() => {
		loadTaskCounts()
		loadList()
	})
	
	onShow(() => {
		loadTaskCounts()
		refresh()
	})
	
	async function loadTaskCounts() {
		try {
			// 获取各状态任务数量
			for (let tab of statusTabs.value) {
				const res = await uniCloud.callFunction({
					name: 'getDisputeList',
					data: {
						role: userStore.role,
						community: userStore.community,
						status: tab.value,
						page: 1,
						pageSize: 1
					}
				})
				
				if (res.result.success) {
					// 获取总数
					const countRes = await uniCloud.callFunction({
						name: 'getStatistics',
						data: {
							role: userStore.role,
							community: userStore.community
						}
					})
					
					// 这里简化处理，实际应该单独查询各状态数量
					if (tab.value === '待回访') {
						tab.count = countRes.result.data?.pendingVisit || 0
					} else if (tab.value === '处理中') {
						// 需要单独统计
						tab.count = 0
					} else if (tab.value === '已化解') {
						tab.count = countRes.result.data?.resolved || 0
					}
				}
			}
		} catch (e) {
			console.error('加载任务数量失败', e)
		}
	}
	
	async function loadList() {
		if (loading.value) return
		
		loading.value = true
		try {
			const res = await uniCloud.callFunction({
				name: 'getDisputeList',
				data: {
					role: userStore.role,
					community: userStore.community,
					status: currentStatus.value,
					page: page.value,
					pageSize: pageSize
				}
			})
			
			if (res.result.success) {
				if (page.value === 1) {
					taskList.value = res.result.data
				} else {
					taskList.value.push(...res.result.data)
				}
				hasMore.value = res.result.hasMore
			}
		} catch (e) {
			console.error('加载任务列表失败', e)
			uni.showToast({
				title: '加载失败',
				icon: 'none'
			})
		} finally {
			loading.value = false
		}
	}
	
	function switchStatus(status) {
		currentStatus.value = status
		page.value = 1
		hasMore.value = true
		loadList()
	}
	
	function refresh() {
		page.value = 1
		hasMore.value = true
		loadList()
	}
	
	function loadMore() {
		if (hasMore.value && !loading.value) {
			page.value++
			loadList()
		}
	}
	
	function goToDetail(id) {
		uni.navigateTo({
			url: `/pages/detail/index?id=${id}`
		})
	}
	
	function formatTime(timestamp) {
		if (!timestamp) return ''
		const date = new Date(timestamp)
		const now = new Date()
		const diff = now - date
		const minutes = Math.floor(diff / 60000)
		
		if (minutes < 1) return '刚刚'
		if (minutes < 60) return `${minutes}分钟前`
		if (minutes < 1440) return `${Math.floor(minutes / 60)}小时前`
		return `${date.getMonth() + 1}-${date.getDate()} ${date.getHours()}:${String(date.getMinutes()).padStart(2, '0')}`
	}
	
	function getStatusClass(status) {
		const map = {
			'待回访': 'status-pending',
			'处理中': 'status-processing',
			'已化解': 'status-resolved',
			'已关闭': 'status-closed'
		}
		return map[status] || ''
	}

	// 分享给朋友
	const onShareAppMessage = () => {
		return {
			title: '社区任务管理',
			path: '/pages/community/index',
			desc: '查看和处理社区矛盾纠纷任务',
			imageUrl: '/static/logo.png'
		}
	}

	defineExpose({
		onShareAppMessage
	})
</script>

